var e=[{id:`L1_1`,type:`dialog`,speaker:null,text:{TWN:`悠菲～西格瑪～救我，他擅自決定簽約啦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L2_1`,type:`dialog`,speaker:`RIBBON_DEBT_NECK_NULL`,text:{KOREA:`유피이이-. 시그마아아-. 도와주세요. 이 사람이 멋대로 계약을 진행시켜요.`,JPN:`ユピイイ。シグマアア。助けてください。この人が勝手に契約を進めます。`,ENG:`Yuppieeeee. Sigmaaaaa. Help. This man is trying to seal the contract without Credere's consent.`,TWN:`什麼？免費供應三餐？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIBBON_DEBT_NECK_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RIBBON_DEBT_NECK_NULL`,text:{KOREA:`네? 삼시 세끼를 무료로 제공한다고요?`,JPN:`はい？　一日三食を無料で提供するんですか？`,ENG:`What? You provide three free meals a day?`,TWN:`請問，可以找朋友一起來嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIBBON_DEBT_NECK_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`RIBBON_DEBT_NECK_NULL`,text:{KOREA:`혹시, 친구초대 이벤트도 있나요?`,JPN:`もしかして、友達招待イベントもありますか？`,ENG:`Is there also, like, a friend-invite event?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIBBON_DEBT_NECK_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};